// Helper: map table name to its C++ type
inline const std::map<std::string, std::string>& eas_table_type_map() {
  static const std::map<std::string, std::string> m = {
      {"Student", "Student"},
      {"Course", "Course"},
      {"Score", "Score"},
      {"Major", "Major"},
  };
  return m;
