// Generic insert function for a given mapped type T
template <typename T>
void add_eas_records(const std::string& table_name,
                     const std::vector<T>& records) {
  // Simple runtime check that the table_name matches the C++ type T we expect
  const auto& m = eas_table_type_map();
  auto it = m.find(table_name);
  if (it == m.end()) {
    throw std::runtime_error("Unknown table name: " + table_name);
  }

  // Connect and insert all records
  sqlite::connect(db_path)
      .and_then([&](auto&& conn) {
        for (const auto& rec : records) {
          // insert<T> will generate INSERT INTO <T-table> ...
          auto res = sqlite::exec(conn, insert(rec));
          if (!res) {
            throw std::runtime_error("Failed to insert record into " +
                                     table_name);
          }
        }
        return result<void>{};
      })
      .value();
}

// Modify a single column by primary key for all tables in this EAS DB.
//
// record_id is passed as std::string so it can handle both numeric PKs
// (CID, ScID, MID) and varchar PKs (SNo); conversion is done internally.
inline void modify_eas_records_by_id(const std::string& table_name,
                                     const std::string& record_id,
                                     const std::string& col_name,
                                     const rfl::json::value& new_value) {
  sqlite::connect(db_path)
      .and_then([&](auto&& conn) -> result<void> {
        if (table_name == "Student") {
          // Student has PK SNo (Varchar<10>)
          auto id_val = record_id;
          // Find the row, update the field, then write it back
          auto res_vec = sqlite::exec(
              conn, read<std::vector<Student>> |
                        where("SNo"_c == id_val));
          if (!res_vec) return res_vec.error();
          auto students = *res_vec;
          if (students.empty()) {
            return std::runtime_error("Student not found");
          }
          auto& stu = students[0];

          // Reflect over Student to set the requested column
          rfl::visit(
              stu, [&](auto& field, const char* name) {
                if (col_name == name) {
                  using FieldType = std::decay_t<decltype(field)>;
                  field = rfl::json::read<FieldType>(new_value);
                }
              });

