#include <gtest/gtest.h>
#include <vector>
#include <string>

#include "batch_insert_products.hpp"

namespace batch_insert_products {

/**
 * Test Case: Test batch insertion of products
 * 
 * Test Scenario:
 * - Generate a list of 50 sample products
 * - Call batch_insert_products with the list
 * - Verify that all 50 products are inserted correctly
 * - Verify that the operation was atomic (all or nothing)
 */
TEST(sqlite, batch_insert_products) {
  // ============ Construct Function Inputs ============

  // Input: List of 50 sample products
  std::vector<Product> products;
  for (int i = 0; i < 50; ++i) {
    products.push_back(Product{
        .product_id = i + 1,
        .name = "Product " + std::to_string(i + 1),
        .price = 10.0f + i,
        .category = "Category " + std::to_string(i % 5),
        .stock = 100 + i});
  }

  // ============ Call Function to Get Return Value ============
  bool success = batch_insert_products(products);

  // ============ Assert to Verify Return Value ============
  EXPECT_TRUE(success);

  // Verify that all products were inserted
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn_result = sqlite::connect("test_db.sqlite");
  ASSERT_TRUE(conn_result.has_value());
  auto conn = conn_result.value();

  const auto count_query = select_from<Product>(count().as<"c">()) | to<int>;
  const auto count_result = count_query(conn);

  EXPECT_TRUE(count_result.has_value());
  EXPECT_EQ(count_result.value(), 50);
}

}  // namespace batch_insert_products

