#include <vector>

namespace batch_insert_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  float price;
  std::string category;
  int stock;
};

/**
 * Function: Perform efficient batch insertion of product data using a transaction.
 * 
 * @param products List of products to insert
 * @return true if all inserts succeed, false otherwise
 */
bool batch_insert_products(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to (and implicitly create) SQLite database "test_db.sqlite".
  const auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = *conn_result;

  // Drop the Product table if it exists, then create it.
  // We don't have the full pipeline API here, so use execute with raw SQL.
  {
    const auto drop_res =
        conn.execute(R"(DROP TABLE IF EXISTS "Product";)");
    if (!drop_res) {
      return false;
    }
  }

  {
    const auto create_res = conn.execute(
        R"(CREATE TABLE "Product"(
             "product_id" INTEGER PRIMARY KEY,
             "name" VARCHAR(100) NOT NULL,
             "price" REAL NOT NULL,
             "category" VARCHAR(50) NOT NULL,
             "stock" INTEGER NOT NULL DEFAULT 0
           );)");
    if (!create_res) {
      return false;
    }
  }

  // Begin transaction
  {
    const auto begin_res = conn.execute("BEGIN TRANSACTION;");
    if (!begin_res) {
      return false;
    }
  }

  // Insert all products; if any insert fails, roll back and return false.
  for (const auto& p : products) {
    const auto insert_res = conn.insert(p);
    if (!insert_res) {
      // Rollback on failure
      conn.execute("ROLLBACK;");
      return false;
    }
  }

  // Commit transaction
  {
    const auto commit_res = conn.execute("COMMIT;");
    if (!commit_res) {
      // If commit fails, try to rollback and report failure
      conn.execute("ROLLBACK;");
      return false;
    }
  }

  return true;
}

}  // namespace batch_insert_products

