#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace delete_inactive_users {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
  std::optional<sqlgen::DateTime> last_login;
  std::string status = "active";
};

int delete_inactive_users() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database "test_db.sqlite"
  sqlite::Connection conn{"test_db.sqlite"};

  // Prepare the delete operation:
  // DELETE FROM User WHERE last_login < DATE('2025-01-01');
  const auto op = sqlite::execute(delete_from<User> |
                                  where("last_login"_c <
                                        sqlite::raw("DATE('2025-01-01')")));

  // Run inside a transaction for safety
  auto [result, rows_affected] = sqlite::transaction(conn, [&]() {
    return op(conn);
  });

  // Return operation result of commit (number of rows deleted)
  return static_cast<int>(rows_affected);
}

} // namespace delete_inactive_users
