#pragma once

#include <filesystem>
#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace test_design_eas_database {

  // Student table:
  // SNo      varchar(10) NOT NULL PRIMARY KEY
  // SName    varchar(30) NOT NULL
  // Sex      int NULL DEFAULT 1
  // Birthday datetime NULL
  // Major    int NULL
  // Scorses  float NULL DEFAULT 0
  // Remark   text NULL
  struct Student {
    sqlgen::PrimaryKey<std::string> SNo;
    std::string SName;
    std::optional<int> Sex;
    std::optional<std::string> Birthday;  // stored as TEXT / DATETIME in SQLite
    std::optional<int> Major;
    std::optional<double> Scorses;
    std::optional<std::string> Remark;
  };

  // Course table:
  // CID    int NOT NULL auto_increment PK
  // CName  varchar(30) NOT NULL
  // Term   int NULL DEFAULT 1
  // CTime  int NULL
  // Credit float NOT NULL DEFAULT 0
  struct Course {
    sqlgen::PrimaryKey<int> CID;
    std::string CName;
    std::optional<int> Term;
    std::optional<int> CTime;
    double Credit;
  };

  // Score table:
  // SNo   varchar(10) NOT NULL  (FK -> Student.SNo)
  // CID   int         NOT NULL  (FK -> Course.CID)
  // Score float       NULL
  // PRIMARY KEY (SNo, CID)
  struct Score {
    std::string SNo;
    int CID;
    std::optional<double> Score;
  };

  void design_eas_database() {
    namespace fs = std::filesystem;

    // Path to SQLite database "test_db.sqlite" in current working directory
    const auto db_path = fs::path("test_db.sqlite");

    // Open / create SQLite database
    auto db = sqlgen::sqlite::Database::from_path(db_path.string());

    // Create Student table
    {
      auto stmt = db.statement(
          "CREATE TABLE IF NOT EXISTS Student ("
          "  SNo      TEXT PRIMARY KEY NOT NULL,"
          "  SName    TEXT NOT NULL,"
          "  Sex      INTEGER DEFAULT 1,"
          "  Birthday DATETIME,"
          "  Major    INTEGER,"
          "  Scorses  REAL DEFAULT 0,"
          "  Remark   TEXT"
          ");");
      stmt.execute();
    }

    // Create Course table
    {
      auto stmt = db.statement(
          "CREATE TABLE IF NOT EXISTS Course ("
          "  CID     INTEGER PRIMARY KEY AUTOINCREMENT NOT NULL,"
          "  CName   TEXT NOT NULL,"
          "  Term    INTEGER DEFAULT 1,"
          "  CTime   INTEGER,"
          "  Credit  REAL NOT NULL DEFAULT 0"
          ");");
      stmt.execute();
    }

    // Create Score table with composite PK and foreign keys
    {
      auto stmt = db.statement(
          "CREATE TABLE IF NOT EXISTS Score ("
          "  SNo    TEXT NOT NULL,"
          "  CID    INTEGER NOT NULL,"
          "  Score  REAL,"
          "  PRIMARY KEY (SNo, CID),"
          "  FOREIGN KEY (SNo) REFERENCES Student(SNo),"
          "  FOREIGN KEY (CID) REFERENCES Course(CID)"
          ");");
      stmt.execute();
    }
  }

}
