namespace query_active_users_posts {

struct User {
  static constexpr const char* tablename = "User";

  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct Post {
  static constexpr const char* tablename = "Post";

  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  sqlgen::DateTime created_at;
};

struct ActiveUser {
  static constexpr const char* viewname = "ActiveUserView";
  static constexpr bool is_view = true;

  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

std::vector<ActiveUser> query_active_users_posts() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to SQLite database
  auto db = sqlgen::sqlite::Database{"test_db.sqlite"};

  // 2. Create User and Post tables if they do not exist
  db.create_table_if_not_exists<User>();
  db.create_table_if_not_exists<Post>();

  // 3. Create or replace the view ActiveUserView implementing the query
  //    SELECT DISTINCT u.user_id, u.username
  //    FROM User u
  //    INNER JOIN Post p ON u.user_id = p.user_id
  //    WHERE p.created_at >= DATE('2025-12-01')
  //      AND p.created_at <= DATE('2025-12-31');
  db.create_view_as<ActiveUser>(
      select(distinct(&User::user_id, &User::username))
          .from<User>()
          .join<Post>(on(&User::user_id == &Post::user_id))
          .where(&Post::created_at >= "2025-12-01"_dt &&
                 &Post::created_at <= "2025-12-31"_dt));

  // 4. Return user information from the view
  return db.select<ActiveUser>();
}

}  // namespace query_active_users_posts
