struct CourseStats {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

// View to store course enrollment statistics
struct CourseStatsView {
  std::string title;
  int student_count;
  std::optional<double> avg_grade;
};

/**
 * Function: Calculate enrollment statistics per course.
 *
 * @return List of course statistics
 */
std::vector<CourseStats> query_course_enrollment_stats() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the specific SQLite database file
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure the tables exist
  conn = conn.and_then(create_table<Course> | if_not_exists)
             .and_then(create_table<Enrollment> | if_not_exists);

  // Perform the aggregation query:
  // SELECT c.title,
  //        COUNT(e.enrollment_id) as student_count,
  //        AVG(e.grade)          as avg_grade
  // FROM Course c
  // LEFT JOIN Enrollment e ON c.course_id = e.course_id
  // GROUP BY c.course_id, c.title;
  const auto result =
      conn.and_then(select(Course::title_,
                           count(Enrollment::enrollment_id_).as("student_count"_c),
                           avg(Enrollment::grade_).as("avg_grade"_c))
                        .from<Course>()
                        .left_join<Enrollment>(Course::course_id_ == Enrollment::course_id_)
                        .group_by(Course::course_id_, Course::title_))
          .and_then(sqlgen::read<std::vector<CourseStatsView>>);

  // Map the view objects to the public CourseStats struct
  std::vector<CourseStats> stats;
  stats.reserve(result.size());
  for (const auto& row : result) {
    stats.push_back(CourseStats{
        .title = row.title,
        .student_count = row.student_count,
        .avg_grade = row.avg_grade,
    });
  }

  return stats;
}

}  // namespace query_course_enrollment_stats

