```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace query_customer_purchase_history {

struct Customer {
  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
  std::string email;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
};

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  sqlgen::ForeignKey<int, Customer, "customer_id"> customer_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  double total_amount;
};

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  sqlgen::ForeignKey<int, Order, "order_id"> order_id;
  sqlgen::ForeignKey<int, Product, "product_id"> product_id;
  int quantity;
};

struct PurchaseHistory {
  std::string product_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
  int quantity;
};


/**
 * Function: Retrieve a customer's purchase history with product details.
 * 
 * @param customer_id ID of the customer to query
 * @return List of purchase history items
 */
std::vector<PurchaseHistory> query_customer_purchase_history(int customer_id) {
  using namespace sqlgen;

  // 1. Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::connect("test_db.sqlite");

  // 2. Create Customer, Order, OrderItem, Product tables (idempotent)
  conn.create_table<Customer>();
  conn.create_table<Product>();
  conn.create_table<Order>();
  conn.create_table<OrderItem>();

  // 3. Query the database to retrieve all products purchased by a specific customer
  //    Matching the reference SQL:
  //    SELECT p.name, o.order_date, oi.quantity
  //    FROM Customer c
  //    JOIN "Order" o ON c.customer_id = o.customer_id
  //    JOIN OrderItem oi ON o.order_id = oi.order_id
  //    JOIN Product p ON oi.product_id = p.product_id
  //    WHERE c.customer_id = ?
  //    ORDER BY o.order_date DESC;
  const auto sql =
      "SELECT p.name AS product_name, "
      "       o.order_date AS order_date, "
      "       oi.quantity AS quantity "
      "FROM Customer c "
      "JOIN \"Order\" o ON c.customer_id = o.customer_id "
      "JOIN OrderItem oi ON o.order_id = oi.order_id "
      "JOIN Product p ON oi.product_id = p.product_id "
      "WHERE c.customer_id = ? "
      "ORDER BY o.order_date DESC;";

  // 4. Read and return the results as a vector of PurchaseHistory
  auto stmt = conn.prepare(sql);
  stmt.bind(1, customer_id);
  auto result = stmt.template fetch_all<PurchaseHistory>();

  return result;
}

}  // namespace query_customer_purchase_history
