  static constexpr const char* viewname = "DailyTrafficView";
  static constexpr bool is_view = true;

  std::string visit_date;
  int total_visits;
  int unique_pages;
};

/**
 * Function: Calculate daily traffic metrics from a log table.
 * 
 * @return List of daily traffic metrics
 */
std::vector<DailyTraffic> query_daily_traffic_metrics() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::Connection{
      sqlite::Credentials{.file = "test_db.sqlite"}};

  // Make sure the PageVisit table exists with the expected schema.
  // This is idempotent: if the table already exists, SQLGEN's
  // `create_table_if_not_exists` will leave it as-is.
  create_table_if_not_exists<PageVisit>(conn);

  // SQL for the daily traffic view, matching the reference query.
  const std::string view_sql =
      "SELECT strftime('%Y-%m-%d', visit_time) AS visit_date, "
      "       COUNT(*) AS total_visits, "
      "       COUNT(DISTINCT url) AS unique_pages "
      "FROM PageVisit "
      "GROUP BY visit_date "
      "ORDER BY visit_date";

  // Create or replace the view in SQLite.
  // SQLGEN provides `create_view_as<ViewType>(connection, sql)`.
  create_view_as<DailyTrafficView>(conn, view_sql);

  // Fetch the aggregated daily traffic rows via the view.
  const auto rows = select<DailyTrafficView>(conn);

  // Convert to the public-facing DailyTraffic struct.
  std::vector<DailyTraffic> result;
  result.reserve(rows.size());
  for (const auto& row : rows) {
    result.push_back(
        DailyTraffic{.visit_date = row.visit_date,
                     .total_visits = row.total_visits,
                     .unique_pages = row.unique_pages});
  }

  return result;
}

}  // namespace query_daily_traffic_metrics
