#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_high_value_orders {

struct Customer {
  static constexpr const char* tablename = "Customer";

  sqlgen::PrimaryKey<int> customer_id;
  std::string name;
};

struct Order {
  // In SQLite tests, the default table name is the struct name if
  // `tablename` is not specified; the SQL reference uses "Order", so
  // be explicit to match it.
  static constexpr const char* tablename = "Order";

  sqlgen::PrimaryKey<int> order_id;
  int customer_id;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

struct OrderView {
  // This struct represents the projection we want to query into.
  static constexpr const char* tablename = "HighValueOrderView";
  static constexpr bool is_view = true;

  sqlgen::PrimaryKey<int> order_id;
  std::string name;
  double total_amount;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> order_date;
};

std::vector<OrderView> query_high_value_orders() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open connection to the SQLite database.
  sqlite::Connection conn{"test_db.sqlite"};

  // Build the SELECT equivalent of:
  //
  // SELECT o.order_id, c.name, o.total_amount, o.order_date
  // FROM "Order" o
  // INNER JOIN Customer c ON o.customer_id = c.customer_id
  // WHERE o.total_amount > 1000
  // ORDER BY o.total_amount DESC;
  //
  // Using sqlgen's expression / DSL helpers.
  auto query =
      Select<OrderView>{}
          .from<Order>()
          .join<Customer>(
              JoinType::Inner,
              // Join predicate: o.customer_id = c.customer_id
              "Order"_t["customer_id"] == "Customer"_t["customer_id"])
          .where("Order"_t["total_amount"] > 1000.0)
          .order_by("Order"_t["total_amount"], OrderDirection::Desc);

  // Execute and return results mapped into OrderView objects.
  return sqlite::select<OrderView>(conn, query);
}

}  // namespace query_high_value_orders
