```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace query_product_sales_report {

struct Product {
  static constexpr const char* tablename = "Product";

  sqlgen::PrimaryKey<int> product_id;
  std::string category;
};

struct Sale {
  static constexpr const char* tablename = "Sale";

  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct CategoryReport {
  std::string category;
  int total_qty;
  double total_amt;
};

struct ProductSalesReport {
  static constexpr const char* viewname = "ProductSalesReport";
  static constexpr bool is_view = true;

  std::string category;
  int total_qty;
  double total_amt;
};

std::vector<CategoryReport> query_product_sales_report() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build the query for the view:
  //
  // SELECT p.category,
  //        SUM(s.quantity) AS total_qty,
  //        SUM(s.amount)   AS total_amt
  // FROM Product p
  // INNER JOIN Sale s ON p.product_id = s.product_id
  // GROUP BY p.category
  // HAVING total_amt > 5000;
  //
  // Using sqlgen, we explicitly write the SQL for the view and then read from it.

  const char* db_path = "test_db.sqlite";

  // Open SQLite connection
  sqlgen::sqlite::Connection connection{db_path};

  // Define (or replace) the view in SQLite
  {
    const char* create_view_sql =
        "CREATE VIEW IF NOT EXISTS ProductSalesReport AS "
        "SELECT p.category AS category, "
        "       SUM(s.quantity) AS total_qty, "
        "       SUM(s.amount) AS total_amt "
        "FROM Product p "
        "INNER JOIN Sale s ON p.product_id = s.product_id "
        "GROUP BY p.category "
        "HAVING total_amt > 5000;";

    auto stmt = connection.prepare(create_view_sql);
    stmt.step();  // execute the CREATE VIEW
  }

  // Now use sqlgen to read from the view into ProductSalesReport objects
  const auto query = sqlgen::read<std::vector<ProductSalesReport>>;

  auto reports = sqlgen::sqlite::execute(connection, query);

  // Map ProductSalesReport to the requested CategoryReport
  std::vector<CategoryReport> result;
  result.reserve(reports.size());
  for (const auto& r : reports) {
    result.push_back(
        CategoryReport{.category = r.category,
                       .total_qty = r.total_qty,
                       .total_amt = r.total_amt});
  }

  return result;
}

}  // namespace query_product_sales_report
