#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite DB "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Base SELECT query
  auto base_query = select<Book>();

  // Dynamically build WHERE clauses based on provided filters
  if (filters.title_keyword.has_value()) {
    // Use LIKE for title search, with wildcard wrapping
    const auto pattern = "%" + *filters.title_keyword + "%";
    base_query = base_query.where("title"_c.like(pattern));
  }

  if (filters.min_year.has_value()) {
    base_query = base_query.where("year"_c >= *filters.min_year);
  }

  if (filters.genre.has_value()) {
    base_query = base_query.where("genre"_c == *filters.genre);
  }

  if (filters.max_price.has_value()) {
    base_query = base_query.where("price"_c <= *filters.max_price);
  }

  // Execute query and read results as a vector of Book
  auto result = conn.and_then(base_query).and_then(read<std::vector<Book>>);

  // If anything failed, return an empty vector (simple error handling)
  if (!result) {
    return {};
  }

  return *result;
}

}  // namespace query_search_books_by_criteria
