  using namespace sqlgen::literals;

  // Cleanup
  auto conn = sqlite::connect("test_db.sqlite").value();
  drop<Product>(conn);
  drop<AuditLog>(conn);
  exec(conn, "DROP TRIGGER IF EXISTS audit_product_update;");

