  EXPECT_TRUE(success);

  // 2. Insert initial data
  Product p1{.product_id = 1, .name = "Widget", .price = 10.0, .stock = 100};
  insert(conn, std::vector{p1});

  // 3. Update the record
  auto update_query = update<Product>("price"_c.set(12.5)) | where("product_id"_c == 1);
  auto update_res = update_query(conn);
