#pragma once

#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_manage_indexes {

  struct Product {
    sqlgen::PrimaryKey<int> product_id;
    std::string sku;
    std::string name;
    std::string category;
    double price;
  };

  bool manage_indexes() {
    try {
      // Connect to the SQLite database "test_db.sqlite"
      auto db = sqlgen::sqlite::Database("test_db.sqlite");

      // Create the Product table if it does not exist
      db.create_table_if_not_exists<Product>();

      // Create indexes with IF NOT EXISTS semantics.
      // sqlgen doesn't have a high‑level index API exposed here,
      // so we execute the raw SQL matching the reference statements.

      // 1. Standard index on category
      db.execute(
          "CREATE INDEX IF NOT EXISTS idx_product_category "
          "ON Product(category);");

      // 2. Unique index on sku
      db.execute(
          "CREATE UNIQUE INDEX IF NOT EXISTS idx_product_sku "
          "ON Product(sku);");

      // 3. Composite index on (name, price)
      db.execute(
          "CREATE INDEX IF NOT EXISTS idx_product_name_price "
          "ON Product(name, price);");

      return true;
    } catch (const std::exception&) {
      // In a real system we might log the exception message.
      return false;
    }
  }

}  // namespace schema_manage_indexes
```

