```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace schema_migration_add_column {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string username;
};

struct UserAfter {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> user_id;
  std::string username;
  std::string phone_number;
  bool is_active;
};

/**
 * Function: Perform schema migration to add new columns.
 *
 * Connects to "test_db.sqlite" and attempts to add:
 *   - phone_number VARCHAR(20)
 *   - is_active INTEGER DEFAULT 1
 *
 * Returns true if the migration steps complete without any unexpected
 * error. "Column already exists" conditions are treated as success.
 *
 * @return true if migration succeeds, false otherwise
 */
bool migration_add_column() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite"
  // The default connect() in tests uses an in-memory DB, so here we use
  // the SQLite helper that accepts a filename.
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }

  auto &conn = *conn_res;

  // Helper lambda to run an ALTER TABLE and ignore "duplicate column" errors.
  auto run_alter_ignoring_duplicate_column =
      [&conn](const std::string &sql) -> bool {
        auto exec_res = conn.exec(sql);
        if (exec_res) {
          return true;
        }

        // Check if the error looks like "duplicate column name" or
        // "column ... already exists". SQLite typically reports:
        //   "duplicate column name: <name>"
        // but different builds may vary slightly, so we check substrings.
        const auto &err = exec_res.error();
        const auto msg  = err.message();

        if (msg.find("duplicate column name") != std::string::npos ||
            msg.find("already exists") != std::string::npos) {
          // Treat as success – schema already migrated for this column.
          return true;
        }

        // Any other error is a real failure.
        return false;
      };

  // Add phone_number column
  const std::string add_phone_sql =
      "ALTER TABLE User ADD COLUMN phone_number VARCHAR(20);";

  if (!run_alter_ignoring_duplicate_column(add_phone_sql)) {
    return false;
  }

  // Add is_active column (SQLite boolean represented as INTEGER)
  const std::string add_is_active_sql =
      "ALTER TABLE User ADD COLUMN is_active INTEGER DEFAULT 1;";

  if (!run_alter_ignoring_duplicate_column(add_is_active_sql)) {
    return false;
  }

  return true;
}

} // namespace schema_migration_add_column
