#include <vector>
#include <string>
#include <optional>

namespace soft_delete_records {

struct Document {
  sqlgen::PrimaryKey<int> doc_id;
  std::string title;
  int is_deleted = 0;
  std::optional<sqlgen::DateTime> deleted_at;
};

bool soft_delete_records(const std::vector<int>& ids) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  if (ids.empty()) {
    // Nothing to do, treat as success
    return true;
  }

  // Connect to the specific SQLite database file "test_db.sqlite"
  auto conn_res = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = std::move(conn_res).value();

  // Build a dynamic WHERE clause: doc_id IN (?, ?, ...)
  std::string where_sql = "doc_id IN (";
  for (std::size_t i = 0; i < ids.size(); ++i) {
    where_sql += (i == 0 ? "?" : ",?");
  }
  where_sql += ")";

  // Prepare the SQL statement using raw SQL (sqlgen primarily focuses on
  // query generation, but we can still execute custom SQL like this).
  auto stmt_res = conn.prepare(
      "UPDATE Document "
      "SET is_deleted = 1, deleted_at = CURRENT_TIMESTAMP "
      "WHERE " +
      where_sql);
  if (!stmt_res) {
    return false;
  }
  auto stmt = std::move(stmt_res).value();

  // Bind the IDs as positional parameters
  for (std::size_t i = 0; i < ids.size(); ++i) {
    if (!stmt.bind(static_cast<int>(i + 1), ids[i])) {
      return false;
    }
  }

  // Execute the update in a single statement
  auto exec_res = stmt.execute();
  if (!exec_res) {
    return false;
  }

  return true;
}

}  // namespace soft_delete_records
