inline auto select_from(const QueryType& _query, const FieldTypes&... _fields) {
  using FieldsType =
      rfl::Tuple<typename internal::GetColType<FieldTypes>::Type...>;
  return SelectFrom<QueryType, Literal<_alias>, FieldsType>{
      .fields_ =
          FieldsType(internal::GetColType<FieldTypes>::get_value(_fields)...),
      .from_ = _query};
}

auto operator()(const auto& _conn) const {
    return begin_transaction_impl(_conn);
  }

template <class ConditionType>
inline auto where(const ConditionType& _cond) {
  return Where<std::remove_cvref_t<ConditionType>>{.condition = _cond};
};

template <class C2>
friend auto operator||(const Condition& _cond1, const Condition<C2>& _cond2) {
  return make_condition(conditions::Or<_ConditionType, C2>{
      .cond1 = _cond1.condition, .cond2 = _cond2.condition});
}

template <class T>
friend auto operator==(const Col&, const T& _t) {
  return transpilation::make_condition(transpilation::conditions::equal(
      transpilation::Col<_name, _alias>{},
      transpilation::to_transpilation_type(_t)));
}

