```cpp
#pragma once

#include <optional>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace transaction_transfer_funds {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
};

bool transfer_funds(int from_account_id, int to_account_id, double amount) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database.
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto conn = std::move(*conn_res);

  // Begin transaction manually so all steps are atomic.
  if (!conn.exec("BEGIN TRANSACTION;")) {
    return false;
  }

  // Helper to rollback and signal failure.
  auto rollback_and_fail = [&conn]() {
    conn.exec("ROLLBACK;");
    return false;
  };

  // 1. Check if from_account has sufficient funds.
  auto from_acc_res =
      conn.and_then(select<Account>.where("account_id"_c == from_account_id)
                         .template limit<1>());
  if (!from_acc_res) {
    return rollback_and_fail();
  }

  auto from_accounts = std::move(*from_acc_res);
  if (from_accounts.empty()) {
    return rollback_and_fail();
  }

  const auto& from_account = from_accounts.front();
  if (from_account.balance < amount) {
    return rollback_and_fail();
  }

  // 2. Deduct from sender.
  auto update_from_res = conn.and_then(
      update<Account>
          .set("balance"_c = "balance"_c - amount)
          .where("account_id"_c == from_account_id &&
                 "balance"_c >= amount));
  if (!update_from_res) {
    return rollback_and_fail();
  }

  // Ensure that one row was actually updated (account existed and had funds).
  if (*update_from_res == 0) {
    return rollback_and_fail();
  }

  // 3. Add to receiver.
  auto update_to_res = conn.and_then(
      update<Account>
          .set("balance"_c = "balance"_c + amount)
          .where("account_id"_c == to_account_id));
  if (!update_to_res) {
    return rollback_and_fail();
  }

  if (*update_to_res == 0) {
    return rollback_and_fail();
  }

  // 4. Commit if everything succeeded.
  if (!conn.exec("COMMIT;")) {
    // If commit fails, attempt rollback.
    conn.exec("ROLLBACK;");
    return false;
  }

  return true;
}

}  // namespace transaction_transfer_funds
