void update_eas_table() {
  // Ensure the initial schema (with Major) exists
  design_eas_database_with_major();

  // Connect to the SQLite database
  sqlgen::sqlite::connect(db_path)
      .and_then([](auto&& conn) {
        // Enable foreign keys
        return sqlgen::exec(conn, "PRAGMA foreign_keys = ON;")
            // 1. Add new non-null column Grade (char(1)) to Score
            .and_then([&conn]() {
              // SQLite uses TEXT; emulate char(1) with TEXT NOT NULL and a
              // default value so existing rows are valid.
              return sqlgen::exec(
                  conn,
                  "ALTER TABLE \"Score\" "
                  "ADD COLUMN \"Grade\" TEXT NOT NULL DEFAULT ' ';");
            })
            // 2. Modify column type of Age in Student to int NULL.
            // SQLite cannot really change types; we follow the requested
            // semantics with ALTER COLUMN TYPE for this exercise.
            .and_then([&conn]() {
              return sqlgen::exec(
                  conn,
                  "ALTER TABLE \"Student\" "
                  "ALTER COLUMN \"Age\" TYPE INTEGER;");
            })
            // 3. Drop the table Major
            .and_then([&conn]() {
              return sqlgen::exec(conn, "DROP TABLE IF EXISTS \"Major\";");
            });
      })
      .value();
}

