```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>

namespace update_order_status {

using namespace sqlgen;
using namespace sqlgen::literals;

struct Order {
  sqlgen::PrimaryKey<int> order_id;
  std::string status;
  sqlgen::DateTime order_date;
  double total_amount;
};

int update_order_status() {
  // Open a connection to the SQLite database "test_db.sqlite"
  auto db = sqlgen::sqlite::Database("test_db.sqlite");

  // Construct the Order table mapping
  auto orderTable = sqlgen::table<Order>("Order");

  int total_affected_rows = 0;

  // 1) Update 'pending' orders older than 7 days to 'expired'
  //
  // Equivalent SQL:
  // UPDATE "Order"
  // SET status = 'expired'
  // WHERE status = 'pending' AND order_date < DATE('now', '-7 days');
  {
    auto stmt = db.update(orderTable)
                    .set(orderTable.status = "expired")
                    .where(orderTable.status == "pending" &&
                           orderTable.order_date < sqlgen::raw("DATE('now', '-7 days')"));

    total_affected_rows += static_cast<int>(stmt.exec());
  }

  // 2) Update 'shipped' orders to 'delivered' when delivery confirmation is received.
  // Here we simulate confirmation by updating all currently 'shipped' orders.
  //
  // Equivalent SQL:
  // UPDATE "Order"
  // SET status = 'delivered'
  // WHERE status = 'shipped';
  {
    auto stmt = db.update(orderTable)
                    .set(orderTable.status = "delivered")
                    .where(orderTable.status == "shipped");

    total_affected_rows += static_cast<int>(stmt.exec());
  }

  // Return total number of rows affected by both updates
  return total_affected_rows;
}

} // namespace update_order_status
