```cpp
#pragma once

#include <ranges>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace schema_create_view_sales_summary {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string name;
  double price;
  int stock;
};

struct Sale {
  sqlgen::PrimaryKey<int, sqlgen::auto_incr> sale_id;
  int product_id;
  int quantity;
  double amount;
};

struct SalesSummary {
  // Mark this as a view type for sqlgen
  static constexpr bool is_view = true;

  // Optional explicit view name (otherwise sqlgen will derive from type)
  static constexpr const char* viewname = "SalesSummary";

  std::string product_name;
  int total_quantity;
  double total_revenue;
};

/**
 * Function: Create a view SalesSummary that aggregates sales by product.
 * 
 * @return true if view creation succeeds, false otherwise
 */
bool create_view_sales_summary() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  // The test suite's default connect() uses an in‑memory DB, but here we
  // explicitly open the requested file.
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return false;
  }
  auto conn = std::move(*conn_result);

  // Ensure underlying tables exist (assumed in the description, but harmless
  // to attempt creation; IF NOT EXISTS is used to avoid errors).
  {
    auto res =
        conn.and_then(create_table<Product> | if_not_exists)
            .and_then(create_table<Sale> | if_not_exists);
    if (!res) {
      return false;
    }
    conn = std::move(*res);
  }

  // Manually drop the view if it already exists to emulate DROP VIEW IF EXISTS
  {
    const std::string drop_sql = "DROP VIEW IF EXISTS SalesSummary;";
    auto res = conn.execute(drop_sql);
    if (!res) {
      return false;
    }
    conn = std::move(*res);
  }

  // Build the SELECT query that defines the view:
  //
  // SELECT p.name AS product_name,
  //        SUM(s.quantity) AS total_quantity,
  //        SUM(s.amount)   AS total_revenue
  // FROM Sale s
  // JOIN Product p ON s.product_id = p.product_id
  // GROUP BY p.name;
  //
  // We'll use the fluent sqlgen query builder and then pass it to create_view_as.
  auto select_query =
      select("name"_c.as("product_name"),
             sum("quantity"_c).as("total_quantity"),
             sum("amount"_c).as("total_revenue"))
          .from<Sale>("s")
          .join<Product>("p", "s.product_id = p.product_id")
          .group_by("name"_c);

  // Create the view using the constructed SELECT.
  // sqlgen will emit: CREATE VIEW SalesSummary AS <select_query>;
  {
    auto res = conn.and_then(create_view_as<SalesSummary>(select_query));
    if (!res) {
      return false;
    }
  }

