```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace right_join_departments_projects {

struct Department {
  sqlgen::PrimaryKey<int> department_id;
  std::string name;
};

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  int department_id;
  std::string name;
};

struct DepProj {
  std::optional<std::string> department_name;
  std::string project_name;
};

/**
 * description: right_join_departments_projects.
 * This function demonstrates how to perform a right join between departments and projects using sqlgen read API.
 * It returns a vector of DepProj structs, where each struct contains the department name (if available) and the project name.
 * Returns: std::vector<DepProj>.
 *
 * Note: SQLite does not support RIGHT JOIN directly. To emulate a RIGHT JOIN that
 * includes all departments (right side) and any matching projects (left side),
 * we perform a LEFT JOIN with Department as the left table and Project as the
 * right table:
 *
 *   SELECT d.name, p.name
 *   FROM Department d
 *   LEFT JOIN Project p ON p.department_id = d.department_id;
 *
 * This returns all departments, with any matching projects, which is the desired
 * behavior for this example.
 */
std::vector<DepProj> right_join_departments_projects() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlite::connect("test_db.sqlite");

  // Define a small helper struct to read the joined columns
  struct Row {
    std::optional<std::string> department_name;
    std::optional<std::string> project_name;
  };

  // Build and execute the LEFT JOIN query that semantically behaves like a RIGHT
  // JOIN over departments (i.e., ensures all departments are included).
  //
  // We explicitly write the SQL here and use sqlgen's low-level query API to
  // map the result into Row, then transform into DepProj.
  const char *sql =
      "SELECT d.name AS department_name, p.name AS project_name "
      "FROM Department d "
      "LEFT JOIN Project p ON p.department_id = d.department_id";

  std::vector<Row> rows;

  // Use the low-level sqlite query API to execute the custom SQL and map into Row
  conn.and_then([&](auto &c) -> sqlite::Result<void> {
        return sqlite::query(
            c,
