#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace generate_sql_dry_run {

struct A {
  sqlgen::PrimaryKey<int> id;
  std::string name;
};

struct B {
  sqlgen::PrimaryKey<int> id;
  int a_id;
  double score;
};

/**
 * This function demonstrates how to build a conditional SQL query.
 * It joins tables A and B, filtering for records where score > 10 and name
 * contains 'x'.
 *
 * It:
 *  1. Constructs a query with joins, where, order_by, and limit
 *  2. Generates an SQL string for SQLite using sqlgen::sqlite::to_sql
 *  3. Verifies that the generated SQL contains expected clauses
 *
 * Returns: the generated SQL string.
 */
std::string generate_sql_dry_run() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite" (for completeness; not used
  // further because this is a dry run / SQL-generation-only example).
  // The connect call is side-effect free with respect to the query string
  // generation: sqlgen::sqlite::to_sql operates purely on the query object.
  [[maybe_unused]] const auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Build a complex read query with:
  //  - INNER JOIN between A and B on A.id = B.a_id
  //  - WHERE: score > 10 AND name LIKE '%x%'
  //  - ORDER BY score DESC, name ASC
  //  - LIMIT 5
  const auto query =
      sqlgen::read<std::vector<A>>() |
      join<B>("id"_c, "a_id"_c) |
      where(("score"_c > 10.0) and like("name"_c, "%x%")) |
      order_by(("score"_c | desc), "name"_c) |
      limit(5);

  // Generate SQL for SQLite (dry run – this does not execute the query).
  const std::string sql = sqlgen::sqlite::to_sql(query);

