```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>
#include <cstdint>

namespace analyze_temporal_data {

struct Event {
  sqlgen::PrimaryKey<int> event_id;
  std::string event_name;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  std::optional<sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S">> end_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> created_at;
};

struct TemporalAnalysis {
  int event_id;
  std::string event_name;
  int start_day;
  int start_month;
  int start_year;
  int start_hour;
  int start_minute;
  int start_second;
  int start_weekday;
  int64_t start_epoch;
  std::optional<double> duration_days;
};

/**
 * @brief Analyze temporal data for a collection of events.
 *
 * Connects to the "test_db.sqlite" SQLite database, ensures the Event table
 * exists, inserts the provided events, then runs a query that:
 *   - Extracts date/time components from start_time
 *   - Computes the weekday and Unix epoch of start_time
 *   - Computes the duration in days between start_time and end_time
 *
 * Only events with a non-null end_time are returned in the result.
 *
 * @param events Vector of Event records to analyze.
 * @return std::vector<TemporalAnalysis> Analysis results for each event that has an end_time.
 */
std::vector<TemporalAnalysis> analyze_temporal_data(const std::vector<Event>& events) {
  using namespace sqlgen;
  using namespace sqlgen::sqlite;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto db = Connection{"test_db.sqlite"};

  // Ensure the Event table exists with the expected schema.
  {
    const auto create_query = CreateTable<Event>{};
    db.exec(create_query);
  }

  // Insert provided events into the Event table.
  if (!events.empty()) {
    const auto insert_query = Insert<Event>{events};
    db.exec(insert_query);
  }

  // Define a lightweight row-mapping struct that matches our SELECT clause.
  struct Row {
    int event_id;
    std::string event_name;
    int start_day;
    int start_month;
    int start_year;
    int start_hour;
    int start_minute;
    int start_second;
    int start_weekday;
    std::int64_t start_epoch;
    double duration_days;
  };

  // Build the SQL query performing temporal analysis using SQLite functions.
  //
  // Notes on SQLite date/time use:
  // - strftime('%d', ...) etc. extract date parts.
  // - weekday = (strftime('%w', ...) + 6) % 7 to emulate MySQL WEEKDAY()
  //   (0 = Monday, 6 = Sunday).
  // - unixepoch(...) gives seconds since 1970-01-01.
  // - julianday(end) - julianday(start) gives fractional days difference.
  const char* analysis_sql =
      "SELECT "
      "  event_id, "
      "  event_name, "
      "  CAST(strftime('%d', start_time) AS INTEGER) AS start_day, "
      "  CAST(strftime('%m', start_time) AS INTEGER) AS start_month, "
      "  CAST(strftime('%Y', start_time) AS INTEGER) AS start_year, "
      "  CAST(strftime('%H', start_time) AS INTEGER) AS start_hour, "
      "  CAST(strftime('%M', start_time) AS INTEGER) AS start_minute, "
      "  CAST(strftime('%S', start_time) AS INTEGER) AS start_second, "
      "  ((CAST(strftime('%w', start_time) AS INTEGER) + 6) % 7) AS start_weekday, "
      "  CAST(unixepoch(start_time) AS INTEGER) AS start_epoch, "
      "  (julianday(end_time) - julianday(start_time)) AS duration_days "
      "FROM Event "
      "WHERE end_time IS NOT NULL;";

  // Execute the raw SQL and fetch into our Row struct.
  const auto select_query = RawSelect<Row>{analysis_sql};
  auto rows = db.fetch(select_query);

  // Transform rows into TemporalAnalysis results.
  std::vector<TemporalAnalysis> results;
  results.reserve(rows.size());

  for (const auto& r : rows) {
    TemporalAnalysis ta;
    ta.event_id = r.event_id;
    ta.event_name = r.event_name;
    ta.start_day = r.start_day;
    ta.start_month = r.start_month;
    ta.start_year = r.start_year;
    ta.start_hour = r.start_hour;
    ta.start_minute = r.start_minute;
    ta.start_second = r.start_second;
    ta.start_weekday = r.start_weekday;
    ta.start_epoch = r.start_epoch;
    ta.duration_days = r.duration_days;
    results.push_back(std::move(ta));
  }

  return results;
}

}  // namespace analyze_temporal_data
