      "  (julianday(end_time) - julianday(start_time)) AS duration_days "
      "FROM Event "
      "WHERE end_time IS NOT NULL;";

  // Execute the raw SQL and fetch into our Row struct.
  const auto select_query = RawSelect<Row>{analysis_sql};
  auto rows = db.fetch(select_query);

  // Transform rows into TemporalAnalysis results.
  std::vector<TemporalAnalysis> results;
  results.reserve(rows.size());

  for (const auto& r : rows) {
    TemporalAnalysis ta;
    ta.event_id = r.event_id;
    ta.event_name = r.event_name;
    ta.start_day = r.start_day;
    ta.start_month = r.start_month;
    ta.start_year = r.start_year;
    ta.start_hour = r.start_hour;
    ta.start_minute = r.start_minute;
    ta.start_second = r.start_second;
    ta.start_weekday = r.start_weekday;
    ta.start_epoch = r.start_epoch;
    ta.duration_days = r.duration_days;
    results.push_back(std::move(ta));
  }

  return results;
}

}  // namespace analyze_temporal_data

