#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace upsert_inventory_items {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
};

/**
 * description: upsert_inventory_items.
 * This function demonstrates how to use upsert (insert or replace) statements in sqlgen write API.
 * It inserts or replaces the given inventory items in the Inventory table.
 */
bool upsert_inventory_items(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // Ensure the Inventory table exists (id as PRIMARY KEY, name & quantity NOT NULL)
  conn = conn.and_then(create_table<Inventory> | if_not_exists);
  if (!conn) {
    return false;
  }

  // Upsert (INSERT OR REPLACE) the given items
  conn = conn.and_then(write(items) | or_replace);
  if (!conn) {
    return false;
  }

  // Read back all items to verify upsert behavior
  const auto read_result = conn.and_then(read<std::vector<Inventory>>);
  if (!read_result) {
    return false;
  }

  // Basic verification: ensure that at least all provided item_ids exist
  const auto& db_items = *read_result;
  for (const auto& input_item : items) {
    const auto found =
        std::find_if(db_items.begin(), db_items.end(),
                     [&](const Inventory& db_item) {
                       return db_item.item_id == input_item.item_id &&
                              db_item.name == input_item.name &&
                              db_item.quantity == input_item.quantity;
                     });
    if (found == db_items.end()) {
      // If any upserted item is not found with expected values, verification fails
      return false;
    }
  }

  return true;
}

}  // namespace upsert_inventory_items
