  double rounded_price;
  double exp_discount;
  double ln_price;
  double log2_quantity;
  double sin_discount;
  double cos_discount;
  double tan_discount;
  double sqrt_quantity;
};

/**
 * Insert products into a SQLite table and run a SELECT that computes
 * various mathematical expressions, returning results as std::vector<MathAnalysis>.
 */
std::vector<MathAnalysis> analyze_mathematical_operations(const std::vector<Product>& products) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the given SQLite database.
  const auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {};
  }
  auto conn = *conn_result;

  // Ensure the Product table exists. This matches the Product struct
  // and lets sqlgen generate the appropriate schema.
  auto pipeline =
      create_table<Product> | if_not_exists
      // Clear existing data for a clean analysis run.
      >> raw("DELETE FROM Product")
      // Insert the provided products.
      >> [&products](auto c) {
           // sqlgen::write returns an rfl::result; we chain writes manually.
           for (const auto& p : products) {
             auto r = sqlgen::write(c, p);
             if (!r) {
               return rfl::result<decltype(c)>::failure(r.error());
             }
           }
           return rfl::result<decltype(c)>::success(c);
         }
      // Run the analysis query.
      >> raw(R"SQL(
            SELECT 
              product_id,
              name,
              ABS(price) AS abs_price,
              CEIL(price) AS ceil_price,
              FLOOR(price) AS floor_price,
              ROUND(price, 2) AS rounded_price,
              EXP(discount_rate/100.0) AS exp_discount,
              LN(price) AS ln_price,
              LOG2(quantity) AS log2_quantity,
              SIN(discount_rate) AS sin_discount,
              COS(discount_rate) AS cos_discount,
              TAN(discount_rate) AS tan_discount,
              SQRT(quantity) AS sqrt_quantity
            FROM Product
          )SQL")
      // Map rows into MathAnalysis structures.
      >> read<std::vector<MathAnalysis>>;

  const auto result = pipeline(conn);
  if (!result) {
    return {};
  }
  return *result;
}

}  // namespace mathematical_operations_analysis
