namespace trim_and_length_validation {

struct UserProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  std::string email;
};

struct ValidatedProfile {
  sqlgen::PrimaryKey<int> user_id;
  std::string trimmed_name;
  std::string trimmed_email;
  int name_length;
  int email_length;
};

/**
 * description: trim_and_length_validation.
 * This function demonstrates how to trim whitespace from string columns and validate their lengths using sqlgen read API.
 * It returns a vector of ValidatedProfile structs, where each struct contains the user_id, trimmed_name, trimmed_email, name_length, and email_length.
 * Returns: std::vector<ValidatedProfile>.
 */
std::vector<ValidatedProfile> trim_and_length_validation() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  const auto conn_result = sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    // If connection fails, return an empty result (caller can decide how to handle)
    return {};
  }
  const auto& conn = *conn_result;

  // Define a lightweight view struct that matches the result columns
  struct RowView {
    sqlgen::PrimaryKey<int> user_id;
    std::string trimmed_name;
    std::string trimmed_email;
    int name_length;
    int email_length;
  };

  // Use sqlgen's read API with a custom SELECT that applies ltrim, rtrim, trim, and length
  // Note:
  // - We use TRIM to get the fully trimmed values for the output
  // - We explicitly use LTRIM and RTRIM in the SELECT to demonstrate their usage
  const auto rows_result = read<std::vector<RowView>>(
      conn,
      "SELECT "
      "  user_id, "
      "  TRIM(name) AS trimmed_name, "
      "  TRIM(email) AS trimmed_email, "
      "  LENGTH(TRIM(name)) AS name_length, "
      "  LENGTH(TRIM(email)) AS email_length "
      "FROM UserProfile");

  if (!rows_result) {
    // If the query fails, return an empty result
    return {};
  }

  const auto& rows = *rows_result;
  std::vector<ValidatedProfile> validated;
  validated.reserve(rows.size());

  for (const auto& row : rows) {
    validated.push_back(ValidatedProfile{
        .user_id = row.user_id,
        .trimmed_name = row.trimmed_name,
        .trimmed_email = row.trimmed_email,
        .name_length = row.name_length,
        .email_length = row.email_length,
    });
  }

  return validated;
}

}  // namespace trim_and_length_validation
