```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace calculate_order_metrics {

struct OrderItem {
  sqlgen::PrimaryKey<int> item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  std::optional<double> discount_rate;
  std::optional<double> tax_rate;
};

struct OrderMetrics {
  int item_id;
  int order_id;
  int product_id;
  double unit_price;
  int quantity;
  double discount_rate;
  double tax_rate;
  double gross_total;
  double discounted_total;
  double final_total;
  double unit_cost;
  int quantity_group;
  double estimated_profit;
};

/**
 * Calculate per-item order metrics by loading the provided items into a SQLite table
 * in the database "test_db.sqlite" and evaluating SQL expressions for totals, discounts,
 * taxes, unit cost, grouping, and estimated profit.
 *
 * This function demonstrates various arithmetic operations (multiplication, division,
 * modulo, addition, subtraction) and ratio calculations using sqlgen.
 *
 * @param items Vector of OrderItem records to analyze.
 * @return std::vector<OrderMetrics> Analysis results for each order item.
 */
std::vector<OrderMetrics> calculate_order_metrics_impl(const std::vector<OrderItem>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the requested SQLite database.
  // If it does not exist, SQLite will create it.
  auto conn_result = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_result) {
    return {};
  }
  auto conn = *conn_result;

  // Ensure the OrderItem table exists in the database.
  // If it already exists, if_not_exists prevents errors.
  {
    auto created =
        (create_table<OrderItem> | if_not_exists)(conn);
    if (!created) {
      return {};
    }
  }

  // Clear any previous content so that metrics are calculated
  // only over the provided `items` vector.
  {
    auto cleared = execute(R"(DELETE FROM "OrderItem";)")(conn);
    if (!cleared) {
      return {};
    }
  }

  // Insert all provided items into the OrderItem table.
  for (const auto& item : items) {
    auto write_res = write(conn, item);
    if (!write_res) {
      return {};
    }
  }

  // Define a local struct mapping to the SELECT result.
  // Field order and types must match the SELECT list below.
  struct RowMetrics {
    int item_id;
    int order_id;
    int product_id;
    double unit_price;
    int quantity;
    double discount_rate;
    double tax_rate;
    double gross_total;
    double discounted_total;
    double final_total;
    double unit_cost;
    int quantity_group;
    double estimated_profit;
  };

  // Use a raw SQL SELECT with arithmetic expressions to compute metrics.
  const char* sql = R"(
    SELECT 
      item_id,
      order_id,
      product_id,
      unit_price,
      quantity,
      COALESCE(discount_rate, 0.0) AS discount_rate,
      COALESCE(tax_rate, 0.0) AS tax_rate,
      (unit_price * quantity) AS gross_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0.0)/100.0)) AS discounted_total,
      (unit_price * quantity * (1 - COALESCE(discount_rate, 0.0)/100.0) *
       (1 + COALESCE(tax_rate, 0.0)/100.0)) AS final_total,
      -- unit_cost as an explicit division to demonstrate arithmetic on columns
      (unit_price * quantity / quantity) AS unit_cost,
      (quantity % 10) AS quantity_group,
      -- simple illustrative profit estimate: 30% margin on unit price
      (unit_price * 0.3) AS estimated_profit
    FROM "OrderItem";
  )";

  auto rows_result = sqlgen::read<std::vector<RowMetrics>>(conn, sql);
  if (!rows_result) {
    return {};
  }

  const auto& rows = *rows_result;
  std::vector<OrderMetrics> result;
  result.reserve(rows.size());

  for (const auto& r : rows) {
    result.push_back(OrderMetrics{
        .item_id = r.item_id,
        .order_id = r.order_id,
        .product_id = r.product_id,
        .unit_price = r.unit_price,
        .quantity = r.quantity,
        .discount_rate = r.discount_rate,
        .tax_rate = r.tax_rate,
        .gross_total = r.gross_total,
        .discounted_total = r.discounted_total,
        .final_total = r.final_total,
        .unit_cost = r.unit_cost,
        .quantity_group = r.quantity_group,
        .estimated_profit = r.estimated_profit,
    });
  }

  return result;
}

}  // namespace calculate_order_metrics
