 * description: join_orders_customers_payments.
 * This function demonstrates how to join three tables (Orders, Customers, and Payments)
 * and return a consolidated view with order_id, customer_name, and amount.
 * It orders the results by amount in descending order.
 * Returns: std::vector<Consolidated>.
 */
std::vector<Consolidated> join_orders_customers_payments() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Open (or create) the SQLite database "test_db.sqlite".
  auto conn = sqlite::Connection{"test_db.sqlite"};

  // Build the query:
  // SELECT o.order_id, c.name AS customer_name, p.amount
  // FROM Order o
  // INNER JOIN Customer c ON o.customer_id = c.customer_id
  // INNER JOIN Payment p ON o.order_id = p.order_id
  // ORDER BY p.amount DESC;
  //
  // The result is mapped into the Consolidated struct.
  const auto query =
      Select<Consolidated>{}
          .from<Order>()
          .join<Customer>(on(&Order::customer_id == &Customer::customer_id))
          .join<Payment>(on(&Order::order_id == &Payment::order_id))
          .order_by(desc(&Payment::amount));

  // Execute the query and fetch the results as a vector of Consolidated.
  return sqlite::get_all<Consolidated>(conn, query);
}

