```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>

namespace inventory_bulk_write_and_read {

struct Inventory {
  sqlgen::PrimaryKey<int> item_id;
  std::string name;
  int quantity;
  std::string location;
};

/**
 * description: inventory_bulk_write_and_read.
 * This function demonstrates how to perform bulk write and read operations on an inventory table.
 * It first drops and recreates the table, then writes the given items to the table.
 * Finally, it reads back the items with quantity > 50, orders them by quantity in descending order,
 * and returns true if at least one item is found.
 * Returns: bool.
 */
bool inventory_bulk_write_and_read(const std::vector<Inventory>& items) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // 1. Connect to the SQLite database file "test_db.sqlite".
  auto conn_res = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn_res) {
    return false;
  }
  auto& conn = conn_res.value();

  // 2. Drop the table if it exists, then recreate it to ensure a clean state.
  //    (Even though the prompt says "assume Inventory table exists", the
  //    function description explicitly asks to drop and recreate it.)
  auto res =
      // Drop if exists
      conn.and_then(drop_table<Inventory> | if_exists)
          // Create table
          .and_then(create_table<Inventory> | if_not_exists);

  if (!res) {
    return false;
  }

  // 3. Bulk write the given items.
  auto write_res = write(conn, items);
  if (!write_res) {
    return false;
  }

  // 4. Read items where quantity > 50, ordered by quantity DESC.
  //    Equivalent to:
  //    SELECT item_id, name, quantity, location
  //    FROM Inventory
  //    WHERE quantity > 50
  //    ORDER BY quantity DESC;
  auto read_res = read<std::vector<Inventory>>(
      conn,
      where("quantity"_c > 50) | order_by("quantity"_c, order::desc));

  if (!read_res) {
    return false;
  }

  const auto& filtered_items = read_res.value();
  return !filtered_items.empty();
}

}  // namespace inventory_bulk_write_and_read
