```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace cascade_delete_demo {

struct Parent {
  sqlgen::PrimaryKey<int> parent_id;
  std::string name;
};

struct Child {
  sqlgen::PrimaryKey<int> child_id;
  sqlgen::ForeignKey<int, Parent, "parent_id"> parent_id;
  std::string note;
};

/**
 * Demonstrates cascade delete behavior in SQLite using foreign key constraints.
 * Returns: bool.
 */
bool cascade_delete_demo() {
  // Connect to SQLite database "test_db.sqlite"
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure foreign keys are enforced in SQLite
  conn.execute("PRAGMA foreign_keys = ON;");

  // Recreate the tables to ensure a clean state
  conn.execute("DROP TABLE IF EXISTS Child;");
  conn.execute("DROP TABLE IF EXISTS Parent;");

  // Create the Parent table
  conn.execute(R"SQL(
    CREATE TABLE Parent (
      parent_id INTEGER PRIMARY KEY,
      name TEXT NOT NULL
    );
  )SQL");

  // Create the Child table with a foreign key that cascades on delete
  conn.execute(R"SQL(
    CREATE TABLE Child (
      child_id INTEGER PRIMARY KEY,
      parent_id INTEGER,
      note TEXT,
      FOREIGN KEY(parent_id) REFERENCES Parent(parent_id) ON DELETE CASCADE
    );
  )SQL");

  // Insert one parent row
  Parent p{.parent_id = 1, .name = "Parent1"};
  conn.insert(p);

  // Insert two child rows referencing the same parent
  Child c1{.child_id = 1, .parent_id = 1, .note = "Child1 of Parent1"};
  Child c2{.child_id = 2, .parent_id = 1, .note = "Child2 of Parent1"};
  conn.insert(c1);
  conn.insert(c2);

  // Verify children exist before deletion
  auto children_before = conn.template select<Child>();
  if (children_before.size() != 2) {
    return false;
  }

  // Delete the parent; this should cascade to Child
  conn.remove<Parent>(p);

  // Verify no child rows remain
  auto children_after = conn.template select<Child>();
  return children_after.empty();
}

}  // namespace cascade_delete_demo
```

