```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>

namespace update_set_operations {

struct Account {
  sqlgen::PrimaryKey<int> account_id;
  double balance;
  std::string status;
};

/**
 * description: update_set_operations.
 * This function demonstrates how to use set operations in update statements using sqlgen write API.
 * It returns true if the update operations are successful, and false otherwise.
 * Returns: bool.
 */
bool update_set_operations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to SQLite database "test_db.sqlite"
  const auto conn = sqlgen::sqlite::connect("test_db.sqlite");
  if (!conn) {
    return false;
  }

  // 1. Create Account table (if it does not already exist)
  const auto created =
      conn.and_then(create_table<Account> | if_not_exists);
  if (!created) {
    return false;
  }

  // 2. Insert some initial data so that updates have something to modify.
  //    We'll overwrite any existing content for a deterministic state.
  const auto cleared = created.and_then(truncate_table<Account>);
  if (!cleared) {
    return false;
  }

  const std::vector<Account> initial_accounts{
      Account{.account_id = 1, .balance = 100.0, .status = "active"},
      Account{.account_id = 2, .balance = 200.0, .status = "inactive"},
      Account{.account_id = 3, .balance = 300.0, .status = "active"},
  };

  const auto inserted = cleared.and_then(write(initial_accounts));
  if (!inserted) {
    return false;
  }

  // 3. Update balances and statuses using set(...)
  // Example operations:
  //   - Increase balance by 50 for account_id == 1 and set status to "vip"
  //   - Set status to "closed" for all accounts with balance < 250
  //
  // The exact fluent API for set/where mirrors the rest of sqlgen operators.
  // We assume something like:
  //
  // update<Account>.set(col(...) = ..., ...) | where(...)
  //
  // is supported by the library (as hinted by other tests).

  // 3a. Update a single row (account_id == 1)
  const auto updated_single =
      inserted.and_then(update<Account> |
                        set("balance"_c = "balance"_c + 50.0,
                            "status"_c = "vip") |
                        where("account_id"_c == 1));
  if (!updated_single) {
    return false;
  }

  // 3b. Update multiple rows with a condition
  const auto updated_multi =
      updated_single.and_then(update<Account> |
                              set("status"_c = "closed") |
                              where("balance"_c < 250.0));
  if (!updated_multi) {
    return false;
  }

  // 4. Verify changes persisted by reading rows back
  const auto accounts_res =
      updated_multi.and_then(sqlgen::read<std::vector<Account>>);
  if (!accounts_res) {
    return false;
  }

  const auto &accounts = *accounts_res;
  if (accounts.size() != 3) {
    return false;
  }

  // Expected:
  //  account 1: balance 150.0, status "closed" (vip then closed because balance<250)
  //  account 2: balance 200.0, status "closed"
  //  account 3: balance 300.0, status "active"
  const auto *acc1 =
      std::find_if(accounts.begin(), accounts.end(),
                   [](const Account &a) { return a.account_id == 1; });
  const auto *acc2 =
      std::find_if(accounts.begin(), accounts.end(),
                   [](const Account &a) { return a.account_id == 2; });
  const auto *acc3 =
      std::find_if(accounts.begin(), accounts.end(),
                   [](const Account &a) { return a.account_id == 3; });

  if (acc1 == accounts.end() || acc2 == accounts.end() ||
      acc3 == accounts.end()) {
    return false;
  }

  const auto approx_equal = [](double a, double b, double eps = 1e-9) {
    return std::fabs(a - b) < eps;
  };

  if (!approx_equal(acc1->balance, 150.0) || acc1->status != "closed") {
    return false;
  }

  if (!approx_equal(acc2->balance, 200.0) || acc2->status != "closed") {
    return false;
  }

  if (!approx_equal(acc3->balance, 300.0) || acc3->status != "active") {
    return false;
  }

  return true;
}

}  // namespace update_set_operations
