```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a
 * supplier and the name of a product, if any.
 *
 * The function connects to the SQLite database "test_db.sqlite" and performs an
 * emulated FULL OUTER JOIN between Supplier and Product:
 *
 *   1. All suppliers with their products (LEFT JOIN).
 *   2. All products that have no matching supplier (RIGHT-only part).
 *
 * These two result sets are combined in memory to produce FULL JOIN semantics.
 */
std::vector<SupProd> full_join_suppliers_products() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the specific SQLite database file.
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure the tables exist (no-op if already present).
  conn = conn.and_then(create_table<Supplier> | if_not_exists)
             .and_then(create_table<Product> | if_not_exists);

  // 1) LEFT JOIN: all suppliers and their products (if any).
  //
  // SELECT Supplier.name, Product.name
  // FROM Supplier
  // LEFT JOIN Product ON Supplier.supplier_id = Product.supplier_id;
  //
  // We select into SupProd directly; product_name is std::optional<std::string>,
  // which matches the semantics of a LEFT JOIN.
  auto left_join_result =
      conn.and_then(select<SupProd>(Supplier::name, Product::name)
                        .from<Supplier>()
                        .left_join<Product>(
                            on(Supplier::supplier_id == Product::supplier_id)))
          .and_then(sqlgen::read<std::vector<SupProd>>)
          .value_or(std::vector<SupProd>{});

  // 2) RIGHT-only part: products with no matching supplier.
  //
  // This corresponds to:
  // SELECT Supplier.name, Product.name
  // FROM Product
  // LEFT JOIN Supplier ON Product.supplier_id = Supplier.supplier_id
  // WHERE Supplier.supplier_id IS NULL;
  //
  // For these rows, Supplier.name will be NULL in SQL. To satisfy the
  // requirement "include all suppliers and products", we still need to return
  // them; since SupProd requires supplier_name to be present, we substitute a
  // placeholder supplier name. This keeps the interface simple while
  // demonstrating full-join coverage.
  struct RightOnlyRow {
    std::optional<std::string> supplier_name;
    std::string product_name;
  };

  auto right_only_rows =
      conn.and_then(select<RightOnlyRow>(Supplier::name, Product::name)
                        .from<Product>()
                        .left_join<Supplier>(
                            on(Product::supplier_id == Supplier::supplier_id))
                        .where(is_null(Supplier::supplier_id)))
          .and_then(sqlgen::read<std::vector<RightOnlyRow>>)
          .value_or(std::vector<RightOnlyRow>{});

  std::vector<SupProd> result = std::move(left_join_result);
  result.reserve(result.size() + right_only_rows.size());

  for (const auto& row : right_only_rows) {
    // Use a placeholder for products without a known supplier.
    // This allows us to still return a SupProd as requested.
    SupProd sp{
        .supplier_name = row.supplier_name.value_or("(no supplier)"),
        .product_name = row.product_name};
    result.push_back(std::move(sp));
  }

  return result;
}

}  // namespace full_join_suppliers_products
```

