 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees(const std::vector<Department>& depts, const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  auto conn = sqlite::connect()
      .and_then(drop<Department> | if_exists)
      .and_then(drop<Employee> | if_exists)
      .and_then(create_table<Department>)
      .and_then(create_table<Employee>)
      .and_then(insert(depts))
      .and_then(insert(emps))
