/**
 * analyze_department_employees
 * Provides data-join analysis between Department and Employee input collections by
 * creating temporary SQL tables, inserting the provided rows, and executing a
 * variety of join queries to produce join-output samples.
 * Returns: JoinAnalysis.
 */
JoinAnalysis analyze_department_employees_impl(const std::vector<Department>& depts,
                                               const std::vector<Employee>& emps) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the requested SQLite DB.
  // The test snippets use sqlite::connect() with an in-memory DB by default,
  // but here we explicitly open "test_db.sqlite" as requested.
  auto conn = sqlgen::sqlite::connect("test_db.sqlite");

  // Ensure the two tables exist and are empty for this analysis run.
  conn = conn.and_then(drop_table<Department> | if_exists);
  conn = conn.and_then(drop_table<Employee> | if_exists);
  conn = conn.and_then(create_table<Department> | if_not_exists);
  conn = conn.and_then(create_table<Employee> | if_not_exists);

  // Insert provided rows.
  conn = conn.and_then(insert(depts));
  conn = conn.and_then(insert(emps));

  JoinAnalysis analysis;

  // Helper lambda to run a query and fetch results into a vector<JoinResult>.
  auto fetch_results = [&](const std::string& sql) -> std::vector<JoinResult> {
    std::vector<JoinResult> rows;

    // Use the underlying SQLite API exposed by sqlgen::sqlite::connection.
    // The connection type used by sqlgen exposes a `get()` to obtain the
    // underlying sqlite3* handle; we keep this minimal and generic.
    sqlite3* handle = conn.get();

    sqlite3_stmt* stmt = nullptr;
    if (sqlite3_prepare_v2(handle, sql.c_str(), -1, &stmt, nullptr) != SQLITE_OK) {
      return rows;
    }

    while (sqlite3_step(stmt) == SQLITE_ROW) {
      JoinResult r;

      // col 0: department_name
      if (sqlite3_column_type(stmt, 0) != SQLITE_NULL) {
        const unsigned char* txt = sqlite3_column_text(stmt, 0);
        if (txt) r.department_name = reinterpret_cast<const char*>(txt);
      }

      // col 1: first_name
      if (sqlite3_column_type(stmt, 1) != SQLITE_NULL) {
        const unsigned char* txt = sqlite3_column_text(stmt, 1);
        if (txt) r.first_name = reinterpret_cast<const char*>(txt);
      }

      // col 2: last_name
      if (sqlite3_column_type(stmt, 2) != SQLITE_NULL) {
        const unsigned char* txt = sqlite3_column_text(stmt, 2);
        if (txt) r.last_name = reinterpret_cast<const char*>(txt);
      }

      // col 3: salary
      if (sqlite3_column_type(stmt, 3) != SQLITE_NULL) {
        r.salary = sqlite3_column_double(stmt, 3);
      }

      rows.push_back(std::move(r));
    }

    sqlite3_finalize(stmt);
    return rows;
  };

  // INNER JOIN: employees with assigned departments
  const std::string inner_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "INNER JOIN Employee e ON d.department_id = e.department_id;";
  analysis.inner_join_results = fetch_results(inner_sql);

  // LEFT JOIN: all employees (even without departments)
  const std::string left_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id;";
  analysis.left_join_results = fetch_results(left_sql);

  // RIGHT JOIN: all departments (even without employees)
  // SQLite does not support RIGHT JOIN directly, so we emulate it by
  // reversing tables in a LEFT JOIN.
  const std::string right_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON e.department_id = d.department_id;";
  analysis.right_join_results = fetch_results(right_sql);

  // FULL JOIN: all departments and all employees.
  // SQLite does not support FULL OUTER JOIN directly,
  // so we emulate it using UNION of left and right side.
  const std::string full_sql =
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Department d "
      "LEFT JOIN Employee e ON e.department_id = d.department_id "
      "UNION "
      "SELECT d.department_name, e.first_name, e.last_name, e.salary "
      "FROM Employee e "
      "LEFT JOIN Department d ON e.department_id = d.department_id;";
  analysis.full_join_results = fetch_results(full_sql);

  return analysis;
}

}  // namespace analyze_department_employees
