#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace in_operator_usage {

struct Status {
  sqlgen::PrimaryKey<int> id;
  int code;
};

/**
 * This function demonstrates IN operator usage.
 * Returns: std::string.
 */
inline std::string in_operator_usage() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build a query selecting Status rows where code IN (1, 2, 3)
  // We use a dummy SQLite connection to leverage sqlgen's SQL generation.
  auto conn = sqlgen::sqlite::connect();

  // Construct the condition: code IN (1, 2, 3)
  auto condition = ("code"_c == 1) || ("code"_c == 2) || ("code"_c == 3);

  // Generate the SQL for this selection into a string.
  // We don't execute the query; we only need the generated SQL.
  std::string sql;
  conn.and_then(select<Status>.where(condition)
                    .inspect([&](const auto& stmt) { sql = stmt.sql; }));

  return sql;
}

}  // namespace in_operator_usage
```

