```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace get_top_products {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  std::string product_name;
  std::string category;
  double price;
};

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Date sale_date;
};

struct TopProduct {
  int product_id;
  std::string product_name;
  std::string category;
  double total_sales;
};

/**
 * Description: This function retrieves the top products based on total sales.
 * Returns: std::vector<TopProduct>.
 */
std::vector<TopProduct> get_top_products(size_t limit_count = 10) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  // and execute an aggregate query to compute total sales
  // per product, ordered by total_sales DESC with a limit.
  const auto result =
      sqlgen::sqlite::connect("test_db.sqlite")
          .and_then([&](auto &conn) {
            // Explicit SQL is used here because we need aggregation,
            // join, ordering and LIMIT for a custom result type (TopProduct).
            const std::string sql =
                "SELECT "
                "  p.product_id, "
                "  p.product_name, "
                "  p.category, "
                "  SUM(p.price * s.quantity) AS total_sales "
                "FROM Product p "
                "INNER JOIN Sales s ON p.product_id = s.product_id "
                "GROUP BY p.product_id, p.product_name, p.category "
                "ORDER BY total_sales DESC "
                "LIMIT ?1;";

            sqlite3_stmt *stmt = nullptr;
            if (sqlite3_prepare_v2(conn.raw(), sql.c_str(),
                                   static_cast<int>(sql.size()),
                                   &stmt, nullptr) != SQLITE_OK) {
              return expected<std::vector<TopProduct>, std::string>(
                  unexpected(sqlite3_errmsg(conn.raw())));
            }

            // Bind the limit parameter
            if (sqlite3_bind_int(stmt, 1,
                                 static_cast<int>(limit_count)) != SQLITE_OK) {
              std::string err = sqlite3_errmsg(conn.raw());
              sqlite3_finalize(stmt);
              return expected<std::vector<TopProduct>, std::string>(
                  unexpected(err));
            }

            std::vector<TopProduct> rows;
            for (;;) {
              const int rc = sqlite3_step(stmt);
              if (rc == SQLITE_ROW) {
                TopProduct tp;
                tp.product_id =
                    sqlite3_column_int(stmt, 0);
                tp.product_name = reinterpret_cast<const char *>(
                    sqlite3_column_text(stmt, 1));
                tp.category = reinterpret_cast<const char *>(
                    sqlite3_column_text(stmt, 2));
                tp.total_sales =
                    sqlite3_column_double(stmt, 3);
                rows.emplace_back(std::move(tp));
              } else if (rc == SQLITE_DONE) {
                break;
              } else {
                std::string err = sqlite3_errmsg(conn.raw());
                sqlite3_finalize(stmt);
                return expected<std::vector<TopProduct>, std::string>(
                    unexpected(err));
              }
            }

            sqlite3_finalize(stmt);
            return expected<std::vector<TopProduct>, std::string>(
                std::move(rows));
          });

  // In this simplified helper, on error we just return an empty vector.
  if (!result) {
    return {};
  }
  return *result;
}

}  // namespace get_top_products
