#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <unordered_map>

namespace update_inventory_stock {

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int stock;
};

bool update_inventory_stock(const std::unordered_map<int, int>& received) {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database
  auto conn_res = sqlite::connect("test_db.sqlite");
  if (!conn_res) return false;
  auto conn = conn_res.value();

  // Ensure the Product table exists (IF NOT EXISTS semantics are used by sqlgen)
  {
    const auto create_stmt = sqlgen::transpilation::to_create_table<Product>();
    auto create_res = conn->exec(create_stmt);
    if (!create_res) return false;
  }

  // Begin a transaction for all updates
  auto txn_res = begin_transaction(conn);
  if (!txn_res) return false;
  auto txn = txn_res.value();

  // Prepare an UPDATE statement using sqlgen
  // Equivalent SQL: UPDATE "Product" SET "stock" = "stock" + ? WHERE "product_id" = ?;
  const auto update_stmt =
      update<Product>()
          .set("stock"_c = "stock"_c + param<int>())
          .where("product_id"_c == param<int>());

  for (const auto& [pid, qty] : received) {
    // Bind parameters: first quantity, then product_id
    auto exec_res = txn->exec(update_stmt, qty, pid);
    if (!exec_res) {
      // Roll back on failure to preserve atomicity
      (void)rollback(txn);
      return false;
    }
  }

  // Commit the transaction
  auto commit_res = commit(txn);
  return commit_res.has_value();
}

}  // namespace update_inventory_stock
