```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace weekday_sales_analysis {

struct Sales {
  sqlgen::PrimaryKey<int> sale_id;
  int product_id;
  int quantity;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> sale_time;
};

struct WeekdayStats {
  int weekday;
  int total_quantity;
};

/**
 * Description: This function analyzes sales data to calculate total quantity sold for each weekday.
 * Returns: std::vector<WeekdayStats>.
 */
std::vector<WeekdayStats> weekday_sales_analysis() {
  using namespace sqlgen;

  // Define a lightweight result mapping struct for the aggregation query.
  struct WeekdayRow {
    int weekday;
    int total_quantity;
  };

  // Open a connection to the SQLite database "test_db.sqlite".
  sqlite::Connection conn{"test_db.sqlite"};

  // Build the SQL aggregation query:
  //   SELECT strftime('%w', sale_time) AS weekday, SUM(quantity) AS total_quantity
  //   FROM Sales
  //   GROUP BY weekday
  //
  // strftime('%w', ...) returns '0' (Sunday) through '6' (Saturday).
  const std::string sql =
      "SELECT CAST(strftime('%w', sale_time) AS INTEGER) AS weekday, "
      "SUM(quantity) AS total_quantity "
      "FROM Sales "
      "GROUP BY weekday;";

  // Execute the query and map rows into WeekdayRow.
  const auto rows = conn.template query<WeekdayRow>(sql);

  // Convert WeekdayRow results into the public WeekdayStats type.
  std::vector<WeekdayStats> result;
  result.reserve(rows.size());
  for (const auto& r : rows) {
    result.push_back(WeekdayStats{.weekday = r.weekday,
                                  .total_quantity = r.total_quantity});
  }

  return result;
}

}  // namespace weekday_sales_analysis
