```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <string>

namespace project_time_tracking {

struct Project {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
};

struct TimeLog {
  sqlgen::PrimaryKey<int> log_id;
  int project_id;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> start_time;
  sqlgen::Timestamp<"%Y-%m-%d %H:%M:%S"> end_time;
};

struct TimeMetrics {
  sqlgen::PrimaryKey<int> project_id;
  std::string name;
  int day;
  int month;
  int year;
  int hour;
  int minute;
  int second;
  double duration_days;
};

/**
 * Description: This function tracks time metrics for each project, including
 * day, month, year, hour, minute, second, and duration in days.
 *
 * It connects to the SQLite database "test_db.sqlite" and:
 *  1. Extracts day/month/year/hour/minute/second from `start_time`
 *  2. Computes days_between(start_time, end_time)
 *  3. Returns weekly grouped metrics (grouping is performed in SQL by
 *     strftime('%Y-%W', start_time), but the function returns the per-row
 *     metrics in TimeMetrics).
 *
 * Returns: std::vector<TimeMetrics>.
 */
std::vector<TimeMetrics> project_time_tracking() {
  using namespace sqlgen;

  // Connect to the SQLite database "test_db.sqlite".
  // The sqlgen::sqlite::Credentials type usually just needs the file path.
  const sqlite::Credentials credentials{.file = "test_db.sqlite"};

  // Open a connection.
  auto conn = sqlite::Connection{credentials};

  // We will compute:
  //   - date/time components using SQLite's strftime
  //   - duration in days via (julianday(end_time) - julianday(start_time))
  //
  // Additionally, to respect "group by project and week for reporting",
  // we include a GROUP BY on project_id and ISO week ("YYYY-WW").
  //
  // For the per-row TimeMetrics result, we can still return one row per
  // (project, week, start_time) aggregation. Since the TimeMetrics struct
  // has no explicit "week" field, we keep the fields as requested.
  //
  // Note: SQLite uses:
  //   strftime('%d', ts) -> day (01-31)
  //   strftime('%m', ts) -> month (01-12)
  //   strftime('%Y', ts) -> year (4-digit)
  //   strftime('%H', ts) -> hour (00-23)
  //   strftime('%M', ts) -> minute (00-59)
  //   strftime('%S', ts) -> second (00-59)
  //
  // To "group by project and week", we can use strftime('%Y-%W', start_time).
  //
  // We aggregate duration_days as the sum of all intervals within each
  // (project, week) bucket. For the date/time components, we can use the
  // minimum start_time in that week (or just any representative, here we
  // use MIN(start_time)) to derive those components.
  //
  // The query below returns one row per (project, week) with:
  //   - representative date/time components from MIN(start_time)
  //   - total duration_days for that week.
  //
  // If you prefer not to aggregate durations, you can drop SUM(...) and
  // GROUP BY and return one result per TimeLog row instead.

  const std::string sql =
      "SELECT "
      "  p.project_id AS project_id, "
      "  p.name AS name, "
      "  CAST(strftime('%d', MIN(t.start_time)) AS INTEGER) AS day, "
      "  CAST(strftime('%m', MIN(t.start_time)) AS INTEGER) AS month, "
      "  CAST(strftime('%Y', MIN(t.start_time)) AS INTEGER) AS year, "
      "  CAST(strftime('%H', MIN(t.start_time)) AS INTEGER) AS hour, "
      "  CAST(strftime('%M', MIN(t.start_time)) AS INTEGER) AS minute, "
      "  CAST(strftime('%S', MIN(t.start_time)) AS INTEGER) AS second, "
      "  SUM(julianday(t.end_time) - julianday(t.start_time)) AS duration_days "
      "FROM Project p "
      "INNER JOIN TimeLog t ON p.project_id = t.project_id "
      "GROUP BY p.project_id, strftime('%Y-%W', t.start_time) "
      "ORDER BY p.project_id, year, month, day;";

  // Execute the query and fetch results into std::vector<TimeMetrics>.
  // sqlgen::sqlite::query automatically maps columns by name to struct
  // fields (case-sensitive match).
  auto results = sqlite::query<TimeMetrics>(conn, sql);

  return results;
}

}  // namespace project_time_tracking
