```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace group_by_with_aggregations {

struct User {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
};

struct Post {
  sqlgen::PrimaryKey<int> post_id;
  int user_id;
  std::string content;
};

struct Stats {
  sqlgen::PrimaryKey<int> user_id;
  std::string name;
  int post_count;
  std::optional<double> avg_length;
};

/**
 * Description: This function retrieves user statistics including post count and average post length.
 * Returns: std::vector<Stats>.
 */
std::vector<Stats> group_by_with_aggregations() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Connect to the SQLite database "test_db.sqlite"
  sqlite::db db{"test_db.sqlite"};

  // We want:
  //   SELECT u.user_id,
  //          u.name,
  //          COUNT(p.post_id) AS post_count,
  //          AVG(length(p.content)) AS avg_length
  //   FROM User u
  //   LEFT JOIN Post p ON u.user_id = p.user_id
  //   GROUP BY u.user_id, u.name;

  auto q = select(
      User::user_id,                         // group key
      User::name,                            // group key
      count(Post::post_id).as<&Stats::post_count>(),
      avg(len(Post::content)).as<&Stats::avg_length>()
  )
      .from<User>()
      .left_join<Post>(User::user_id == Post::user_id)
      .group_by(User::user_id, User::name);

  return db.execute<Stats>(q);
}

}  // namespace group_by_with_aggregations
