 * This function demonstrates creating a table from a select query.
 * Returns: query value.
 */
inline auto create_table_as_select() {
  using namespace sqlgen;
  using namespace sqlgen::literals;

  // Build:
  //   CREATE TABLE "Target" AS
  //   SELECT "value" FROM "Source" WHERE ("value" > 100)
  const auto query =
      create_table_as<Target>(
          select(&Source::value)
              .from<Source>()
              .where(c<&Source::value> > 100));

  return query.value();
}

}  // namespace create_table_as_select
